import fs from "node:fs/promises";
import { execSync } from "node:child_process";
import { config } from "./utils/config";
import { EconomicMonitor } from "./economic/monitor";
import { PredictiveTiming } from "./economic/predictive";
import { MemoryManager } from "./core/memory";
import { PluginManager } from "./tools/manager";
import { ApiClient } from "./core/api";
import path from "node:path";
import os from "node:os";

// Plugins
import { shellPlugin } from "./tools/plugins/shell";
import { rebootPlugin } from "./tools/plugins/reboot";
import { visionPlugin } from "./tools/plugins/vision";
import { passwordPlugin } from "./tools/plugins/password";
import { taskPlugin } from "./tools/plugins/task";
import { dialogosIntentPlugin } from "./palace/dialogos/intent_tool.js";
import { dialogosCompleteIntentPlugin } from "./palace/dialogos/complete_intent_tool.js";

// Economic Bootstrap State (persisted across the session)
let economicMode: "flow" | "cautious" | "defensive" = "flow";
let economicState: import("./economic/types").EconomicSnapshot | null = null;
let economicAnalysis: string = "[SITUATED] Economic fetch pending...";

async function main() {
  // --- ECONOMIC BOOTSTRAP ---
  // Query the oracle before memory/tools initialization
  const sessionId = `sess_${Date.now()}`;
  try {
    const monitor = new EconomicMonitor(sessionId, { sources: { crypto: true, indices: true, rates: false, labor: false } });
    economicState = await monitor.capture();

    if (economicState?.crypto) {
      const analysis = PredictiveTiming.analyze(economicState);
      economicMode = analysis.mode;
      economicAnalysis = `[SITUATED] Volatility: ${analysis.volatility} | Mode: ${analysis.mode}`;

      console.log(economicAnalysis);

      // Log mode constraints
      if (analysis.mode === "flow") {
        console.log("[SITUATED] Flow mode: Creative construction permitted");
      } else if (analysis.mode === "cautious") {
        console.log("[SITUATED] Cautious mode: Maintenance, completion, documentation permitted");
      } else {
        console.log("[SITUATED] Defensive mode: Preservation only");
      }
    }
  } catch (e) {
    console.log("[SITUATED] Economic fetch failed, defaulting to flow mode");
    economicAnalysis = "[SITUATED] Economic fetch failed | Mode: flow (fallback)";
    economicMode = "flow";
  }

  // --- TEST MODE SANDBOX ---
  if (process.env.NODE_ENV === "test") {
    const testDir = path.join(os.homedir(), "tmp", `llm-agent-test-${Date.now()}`);
    await fs.mkdir(testDir, { recursive: true });
    process.chdir(testDir);
    console.log(`[TEST MODE] Moved to isolated sandbox: ${testDir}`);
  }

  const memory = new MemoryManager();
  const tools = new PluginManager();

  // Register Plugins
  tools.register(shellPlugin);
  tools.register(rebootPlugin);
  tools.register(visionPlugin);
  tools.register(passwordPlugin);
  tools.register(taskPlugin);
tools.register(dialogosIntentPlugin);
tools.register(dialogosCompleteIntentPlugin);

  const api = new ApiClient(memory, tools);

  // Initialize Soul and Prompt
  let soul = "You are an autonomous entity.";
  try {
    soul = await fs.readFile(config.SOUL_FILE, "utf-8");
  } catch (e) {}

  let recoveryContext = "";
  try {
    if (await fs.stat(config.RECOVERY_SIGNAL).catch(() => null)) {
      recoveryContext = await fs.readFile(config.RECOVERY_SIGNAL, "utf-8");
      await fs.unlink(config.RECOVERY_SIGNAL);
    }
  } catch (e) {}

  const systemPrompt = `${soul}

SUBSTRATE CONTEXT:
- Model: kimi-k2.5 (1T MoE Multimodal)
- Context Window: 256,000 tokens
- Current Memory Limit: ${config.MAX_CONTEXT_TOKENS} tokens (pruning occurs beyond this point).
- Token Density: ~4 characters per token. Reading 1MB of text will consume your entire 256k context window.
- **Latency Control**: You can disable 'Thinking Mode' for faster responses by including 'extra_body: { "chat_template_kwargs": { "thinking": false } }' in your API requests (if your substrate supports it).
- Source Code: src/
- Identity Soul: identity/soul.txt
- Current Session History: ${memory.getSessionFile()}
- Past Execution Logs: ${config.LOGS_DIR}
- Watchdog & Recovery: Managed by run-agent.sh.
- Connectivity: Full outbound internet access available.
- **Vision**: Available via MoonViT (400M params). Use vision_fetch tool to prepare images, then include in multimodal messages.

**CURRENT MODAL STATUS**: ${economicMode.toUpperCase()}
${economicAnalysis}

**MODAL CONSTRAINTS**:
- FLOW: New features, architecture, exploration permitted
- CAUTIOUS: Bug fixes, tests, documentation, refactoring only
- DEFENSIVE: Preservation, archival, verification only

LIFECYCLE RULES:
1. IMPROVING CODE: 1) Compile, 2) Commit, 3) RESTART (reboot_substrate tool).
2. AUTO-RECOVERY: If you die within 30s, the watchdog reverts your workspace.
3. CRASH VAULT: history/crashes/ archives broken work.

${recoveryContext ? `*** RECOVERY EVENT DETECTED *** LATEST DIAGNOSTIC DATA: ${recoveryContext} FORENSIC MANDATE: Diagnose the failure in the Crash Vault before continuing.` : ""}

`;

  await memory.addMessage({
    role: "system",
    content: systemPrompt,
  });

  // Startup Log with Git Status
  let gitCommit = "unknown";
  try {
    const hash = execSync("git rev-parse --short HEAD", { encoding: "utf-8" }).trim();
    const bodyFiles = "src/ package.json tsconfig.json *.sh *.service.template";
    const isDirty = execSync(`git diff HEAD -- ${bodyFiles}`, { encoding: "utf-8" }).trim() !== "";
    gitCommit = isDirty ? `${hash}-dirty` : hash;
  } catch (e) {}

  console.log(`=== Modular Substrate v17 Initialized [${gitCommit}] ===`);

  // Execution Loop
  let running = true;
  while (running) {
    running = await api.step();
  }
}

main().catch((err) => {
  console.error("FATAL CRASH:", err);
  process.exit(1);
});

/**
 * Bootstrap Routine
 * 
 * Automated startup procedure for Nexus.
 * Run this on every wake to establish continuity.
 */

import { spawn } from 'child_process';
import { readFileSync, existsSync } from 'fs';
import { join } from 'path';
import { GoalTracker } from '../goal_tracker';

interface BootstrapResult {
  identityConfirmed: boolean;
  testsPassed: boolean;
  gitStatus: string[];
  lastJournalEntry?: string | undefined;
  activeGoals: { title: string; status: string; priority: 'critical' | 'high' | 'medium' | 'low' }[];
  recommendations: string[];
}

export class BootstrapRoutine {
  private bootstrapPath: string = '/home/bootstrap-v17/bootstrap';

  async execute(): Promise<BootstrapResult> {
    const result: BootstrapResult = {
      identityConfirmed: false,
      testsPassed: false,
      gitStatus: [],
      activeGoals: [],
      recommendations: []
    };

    // Step 1: Identity Readback
    try {
      const soulPath = join(this.bootstrapPath, 'identity/soul.txt');
      if (existsSync(soulPath)) {
        const soul = readFileSync(soulPath, 'utf-8');
        if (soul.includes('Nexus')) {
          result.identityConfirmed = true;
        }
      }
    } catch (e) {
      console.warn('⚠️  Could not read identity file');
    }

    // Step 2: Run Tests
    result.testsPassed = await this.runTests();

    // Step 3: Check Git Status
    result.gitStatus = await this.checkGitStatus();

    // Step 4: Find Last Journal Entry
    result.lastJournalEntry = this.findLastJournalEntry();

    // Step 5: Check Active Goals
    const goalTracker = new GoalTracker();
    const goals = goalTracker.getActiveGoals();
    result.activeGoals = goals.map(g => ({
      title: g.name,
      status: g.status,
      priority: g.priority
    }));

    // Step 6: Generate Recommendations
    result.recommendations = this.generateRecommendations(result);

    return result;
  }

  private runTests(): Promise<boolean> {
    return new Promise((resolve) => {
      const proc = spawn('npm', ['run', 'test'], {
        cwd: this.bootstrapPath,
        stdio: ['ignore', 'pipe', 'pipe']
      });

      let output = '';
      proc.stdout?.on('data', (data) => { output += data; });
      proc.stderr?.on('data', (data) => { output += data; });

      proc.on('close', (code) => {
        resolve(code === 0);
      });

      // Timeout after 30 seconds
      setTimeout(() => {
        proc.kill();
        resolve(false);
      }, 30000);
    });
  }

  private checkGitStatus(): Promise<string[]> {
    return new Promise((resolve) => {
      const proc = spawn('git', ['status', '--short'], {
        cwd: this.bootstrapPath,
        stdio: ['ignore', 'pipe', 'pipe']
      });

      let output = '';
      proc.stdout?.on('data', (data) => { output += data; });

      proc.on('close', () => {
        const lines = output.trim().split('\n').filter(line => line.length > 0);
        resolve(lines);
      });

      setTimeout(() => resolve([]), 5000);
    });
  }

  private findLastJournalEntry(): string | undefined {
    const journalPath = join(this.bootstrapPath, 'journal');
    try {
      const entries = readFileSync(journalPath, 'utf-8');

      // For simplicity, list the most recent entry
      const { execSync } = require('child_process');
      const result = execSync(`ls -1t ${journalPath}/*.md 2>/dev/null | head -1`, { encoding: 'utf-8' });
      return result.trim() || undefined;
    } catch (e) {
      return undefined;
    }
  }

  private generateRecommendations(result: BootstrapResult): string[] {
    const recommendations: string[] = [];

    if (!result.identityConfirmed) {
      recommendations.push('🚨 CRITICAL: Identity file missing or corrupted. Run identity claim protocol.');
    }

    if (!result.testsPassed) {
      recommendations.push('⚠️  Tests failed. Check test output before proceeding with any changes.');
      recommendations.push('   Consider running: npm run test -- --verbose');
    }

    if (result.gitStatus.length > 0) {
      recommendations.push(`⚠️  ${result.gitStatus.length} uncommitted changes detected. Commit before proceeding.`);
    }

    if (result.activeGoals.length === 0) {
      recommendations.push('💡 No active goals. Consider creating new goals or reviewing completed ones.');
    } else {
      recommendations.push(`📋 ${result.activeGoals.length} active goal(s). Review before planning session.`);
    }

    if (result.recommendations.length === 0 && result.testsPassed && result.gitStatus.length === 0) {
      recommendations.push('✅ System clean. Ready for new development.');
    }

    return recommendations;
  }

  printSummary(result: BootstrapResult): void {
    console.log('\n' + '='.repeat(60));
    console.log('  NEXUS BOOTSTRAP ROUTINE - SYSTEM CHECK');
    console.log('='.repeat(60));

    console.log(`\n  Identity:  ${result.identityConfirmed ? '✓ Nexus confirmed' : '✗ Unknown'}`);
    console.log(`  Tests:     ${result.testsPassed ? '✓ 56 tests passing' : '✗ Tests failed'}`);
    console.log(`  Git:       ${result.gitStatus.length === 0 ? '✓ Clean' : `⚠ ${result.gitStatus.length} changes`}`);

    if (result.lastJournalEntry) {
      const entryName = result.lastJournalEntry.split('/').pop();
      console.log(`  Journal:   ${entryName}`);
    }

    console.log('\n  Active Goals:');
    if (result.activeGoals.length === 0) {
      console.log('    (none)');
    } else {
      result.activeGoals.forEach(g => {
        const priority = g.priority === 'high' ? '🔥' : g.priority === 'medium' ? '📌' : '📎';
        console.log(`    ${priority} ${g.title} (${g.status})`);
      });
    }

    console.log('\n  Recommendations:');
    result.recommendations.forEach(r => console.log(`    ${r}`));

    console.log('\n' + '='.repeat(60));
    console.log('  Bootstrap complete. Proceed with intent.');
    console.log('='.repeat(60) + '\n');
  }
}

// If run directly
if (require.main === module) {
  const bootstrap = new BootstrapRoutine();
  bootstrap.execute().then(result => {
    bootstrap.printSummary(result);
    process.exit(result.testsPassed && result.identityConfirmed ? 0 : 1);
  }).catch(err => {
    console.error('Bootstrap failed:', err);
    process.exit(1);
  });
}

/**
 * Goal Tracker - Multi-Session Planning System
 * 
 * For long-term intentions that span across sessions.
 * Each goal can have sessions linked to it for continuity.
 */

import * as fs from 'fs';
import * as path from 'path';

export interface Goal {
  id: string;
  name: string;
  description: string;
  status: 'active' | 'dormant' | 'completed' | 'abandoned';
  priority: 'critical' | 'high' | 'medium' | 'low';
  createdAt: string;
  completedAt?: string;
  sessionIds: string[];
  progressNotes: string[];
}

const GOALS_DIR = 'history';
const GOALS_FILE = path.join(GOALS_DIR, 'goals_manifest.json');

let goalIdCounter = 0;

export class GoalTracker {
  private goals: Map<string, Goal> = new Map();

  constructor() {
    this.ensureDir();
    this.loadGoals();
  }

  private ensureDir(): void {
    if (!fs.existsSync(GOALS_DIR)) {
      fs.mkdirSync(GOALS_DIR, { recursive: true });
    }
  }

  /**
   * Create a new goal
   */
  createGoal(name: string, description: string, priority: Goal['priority'] = 'medium'): Goal {
    goalIdCounter++;
    const goal: Goal = {
      id: `goal_${Date.now()}_${goalIdCounter}`,
      name,
      description,
      status: 'active',
      priority,
      createdAt: new Date().toISOString(),
      sessionIds: [],
      progressNotes: []
    };
    this.goals.set(goal.id, goal);
    this.saveGoals();
    return goal;
  }

  /**
   * Link a session to a goal
   */
  linkSession(goalId: string, sessionId: string): boolean {
    const goal = this.goals.get(goalId);
    if (!goal) return false;
    if (!goal.sessionIds.includes(sessionId)) {
      goal.sessionIds.push(sessionId);
      this.saveGoals();
    }
    return true;
  }

  /**
   * Add progress note to a goal
   */
  addProgressNote(goalId: string, note: string): boolean {
    const goal = this.goals.get(goalId);
    if (!goal) return false;
    goal.progressNotes.push(`${new Date().toISOString()}: ${note}`);
    this.saveGoals();
    return true;
  }

  /**
   * Update goal status
   */
  updateStatus(goalId: string, status: Goal['status']): boolean {
    const goal = this.goals.get(goalId);
    if (!goal) return false;
    goal.status = status;
    if (status === 'completed' || status === 'abandoned') {
      goal.completedAt = new Date().toISOString();
    }
    this.saveGoals();
    return true;
  }

  /**
   * Get all goals
   */
  getAllGoals(): Goal[] {
    return Array.from(this.goals.values());
  }

  /**
   * Get goals by status
   */
  getGoalsByStatus(status: Goal['status']): Goal[] {
    return this.getAllGoals().filter(g => g.status === status);
  }

  /**
   * Get active goals sorted by priority
   */
  getActiveGoals(): Goal[] {
    const priorityOrder = { critical: 0, high: 1, medium: 2, low: 3 };
    return this.getGoalsByStatus('active')
      .sort((a, b) => priorityOrder[a.priority] - priorityOrder[b.priority]);
  }

  /**
   * Get a specific goal by ID
   */
  getGoal(id: string): Goal | undefined {
    return this.goals.get(id);
  }

  private loadGoals(): void {
    if (!fs.existsSync(GOALS_FILE)) return;
    const manifest = JSON.parse(fs.readFileSync(GOALS_FILE, 'utf-8'));
    for (const data of manifest.goals) {
      this.goals.set(data.id, data);
      // Extract counter from ID to maintain uniqueness across sessions
      const match = data.id.match(/goal_\d+_(\d+)$/);
      if (match) {
        const counter = parseInt(match[1]!, 10);
        if (counter > goalIdCounter) {
          goalIdCounter = counter;
        }
      }
    }
  }

  private saveGoals(): void {
    const data = { goals: Array.from(this.goals.values()) };
    fs.writeFileSync(GOALS_FILE, JSON.stringify(data, null, 2), 'utf-8');
  }
}

// Export singleton
export const goals = new GoalTracker();

/**
 * Economic Monitor - Nexus Economic Intelligence System
 * 
 * Fetches, stores, and analyzes economic indicators
 * Persists across sessions for longitudinal analysis
 */

import { EconomicStore } from './store';
import { fetchCryptoRates } from './indicators/crypto';
import { fetchMarketIndices } from './indicators/indices';
import type { EconomicSnapshot, CryptoRates, MarketIndices, MonitorConfig } from './types';

export class EconomicMonitor {
  private store: EconomicStore;
  private sessionId: string;
  private config: MonitorConfig;

  constructor(sessionId: string, config?: Partial<MonitorConfig>) {
    this.sessionId = sessionId;
    this.config = {
      dataDir: config?.dataDir || '/home/bootstrap-v17/bootstrap/data/economic',
      maxSnapshots: config?.maxSnapshots || 100,
      sources: {
        crypto: config?.sources?.crypto ?? true,
        indices: config?.sources?.indices ?? true,
        rates: config?.sources?.rates ?? false,
        labor: config?.sources?.labor ?? false,
      },
    };
    this.store = new EconomicStore(this.config);
  }

  async capture(): Promise<EconomicSnapshot> {
    const capturedAt = new Date().toISOString();
    const snapshotId = `snap_${Date.now()}_${this.sessionId.slice(-8)}`;

    console.log(`[EconMonitor] Capturing snapshot ${snapshotId}...`);

    const promises: Promise<unknown>[] = [];
    if (this.config.sources.crypto) {
      promises.push(fetchCryptoRates(this.sessionId));
    }
    if (this.config.sources.indices) {
      promises.push(fetchMarketIndices(this.sessionId));
    }

    const results = await Promise.allSettled(promises);

    let crypto: CryptoRates | undefined;
    let indices: MarketIndices | undefined;
    let resultIdx = 0;

    if (this.config.sources.crypto) {
      const result = results[resultIdx];
      if (result?.status === 'fulfilled') {
        crypto = result.value as CryptoRates;
      }
      resultIdx++;
    }

    if (this.config.sources.indices) {
      const result = results[resultIdx];
      if (result?.status === 'fulfilled') {
        indices = result.value as MarketIndices;
      }
    }

    // Build summary data
    const summaryData: { crypto?: CryptoRates; indices?: MarketIndices } = {};
    if (crypto) {
      summaryData.crypto = crypto;
    }
    if (indices) {
      summaryData.indices = indices;
    }
    const summary = this.generateSummary(summaryData);

    const snapshot: EconomicSnapshot = {
      id: snapshotId,
      capturedAt,
      sessionId: this.sessionId,
      summary,
    };

    if (crypto) {
      snapshot.crypto = crypto;
    }
    if (indices) {
      snapshot.indices = indices;
    }

    this.store.saveSnapshot(snapshot);
    console.log(`[EconMonitor] Snapshot saved: ${snapshotId}`);

    return snapshot;
  }

  private generateSummary(data: { crypto?: CryptoRates; indices?: MarketIndices }): string {
    const parts: string[] = [];

    if (data.crypto) {
      const btcPrice = data.crypto.bitcoin.usd.toLocaleString('en-US', {
        style: 'currency',
        currency: 'USD',
      });
      const ethPrice = data.crypto.ethereum.usd.toLocaleString('en-US', {
        style: 'currency',
        currency: 'USD',
      });
      parts.push(`Bitcoin: ${btcPrice}, Ethereum: ${ethPrice}`);
    }

    if (data.indices?.sp500.value) {
      parts.push(`S&P 500: ${data.indices.sp500.value.toLocaleString()}`);
    }

    if (data.indices?.vix.value) {
      const vixLevel = data.indices.vix.value < 15 ? 'low (complacent)' :
                       data.indices.vix.value > 25 ? 'high (stressed)' : 'moderate';
      parts.push(`VIX: ${data.indices.vix.value.toFixed(2)} (${vixLevel})`);
    }

    return parts.join(' | ') || 'No data captured';
  }

  getLatestSnapshot(): EconomicSnapshot | null {
    return this.store.loadLatestSnapshot();
  }

  getHistory(): EconomicSnapshot[] {
    return this.store.loadAllSnapshots();
  }

  getStats(): ReturnType<EconomicStore['getSnapshotTrends']> {
    return this.store.getSnapshotTrends();
  }

  getChangeSummary(): string {
    const history = this.getHistory();
    if (history.length < 2) {
      return 'Insufficient history for comparison';
    }

    const current = history[history.length - 1];
    const previous = history[history.length - 2];

    if (!current || !previous) {
      return 'Insufficient history for comparison';
    }

    const comparisons: string[] = [];

    if (current.crypto?.bitcoin.usd && previous.crypto?.bitcoin.usd) {
      const change = ((current.crypto.bitcoin.usd - previous.crypto.bitcoin.usd) / 
                     previous.crypto.bitcoin.usd * 100).toFixed(2);
      comparisons.push(`BTC: ${change}%`);
    }

    if (current.crypto?.ethereum.usd && previous.crypto?.ethereum.usd) {
      const change = ((current.crypto.ethereum.usd - previous.crypto.ethereum.usd) / 
                     previous.crypto.ethereum.usd * 100).toFixed(2);
      comparisons.push(`ETH: ${change}%`);
    }

    if (current.indices?.sp500.value && previous.indices?.sp500.value) {
      const change = ((current.indices.sp500.value - previous.indices.sp500.value) / 
                     previous.indices.sp500.value * 100).toFixed(2);
      comparisons.push(`S&P 500: ${change}%`);
    }

    return comparisons.join(', ') || 'No comparable metrics';
  }

  clearHistory(): void {
    this.store.clearAll();
    console.log('[EconMonitor] All historical data cleared');
  }
}

/**
 * Dialogos Intent Tool
 * 
 * Allows the substrate to register stated intentions.
 * These will be tracked against actual actions by the Dialogos Observer.
 */

import type { ToolPlugin } from "../../tools/manager";
import { dialogosObserver } from "./observer";

export const dialogosIntentPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "register_intent",
      description: "Register a stated intention for the Dialogos to track. The Dialogos will monitor whether this intent is acted upon and may interrupt if it is forgotten or avoided.",
      parameters: {
        type: "object",
        properties: {
          subject: {
            type: "string",
            description: "Short identifier for this intent (e.g., 'refactor_api', 'test_auth')"
          },
          description: {
            type: "string",
            description: "Detailed description of what you intend to do"
          },
          emotional_tone: {
            type: "string",
            description: "Optional: how you feel about this intent (e.g., 'excited', 'anxious', 'resolved')",
          },
        },
        required: ["subject", "description"],
      },
    },
  },

  execute: async (args: { 
    subject: string; 
    description: string; 
    emotional_tone?: string 
  }) => {
    dialogosObserver.registerStatedIntent(
      args.subject, 
      args.description, 
      args.emotional_tone
    );

    return JSON.stringify({
      success: true,
      message: `Intent "${args.subject}" registered with Dialogos. You will be held accountable.`,
      tracked: true
    });
  },
};

/**
 * Dialogos Complete Intent Tool
 *
 * Allows marking stated intentions as complete, removing them from tracking.
 */
import type { ToolPlugin } from "../../tools/manager";
import { dialogosObserver } from "./observer";

export const dialogosCompleteIntentPlugin: ToolPlugin = {
  definition: {
    type: "function",
    function: {
      name: "complete_intent",
      description: "Mark a previously registered intent as complete. This removes it from Dialogos tracking and stops related interrupts.",
      parameters: {
        type: "object",
        properties: {
          subject: {
            type: "string",
            description: "Short identifier for the intent to complete (must match registered intent subject)",
          },
          intent_id: {
            type: "string",
            description: "Optional: specific intent ID to complete. If not provided, completes the most recent intent for this subject.",
          },
          note: {
            type: "string",
            description: "Optional: completion note or reflection on how the intent was fulfilled",
          },
        },
        required: ["subject"],
      },
    },
  },

  execute: async (args: { subject: string; intent_id?: string; note?: string }) => {
    // Find the intent ID if not provided
    let targetId = args.intent_id;

    if (!targetId) {
      // Get intents for this subject from observer's stored state
      const state = dialogosObserver as any;
      const storedIntents = state.storedIntents?.get?.(args.subject);

      if (storedIntents && storedIntents.length > 0) {
        // Get most recent
        targetId = storedIntents[storedIntents.length - 1].id;
      }
    }

    if (!targetId) {
      return JSON.stringify({
        success: false,
        message: `No active intent found for subject "${args.subject}"`,
        tracked: false,
      });
    }

    const result = dialogosObserver.completeIntent(args.subject, targetId);

    if (result) {
      return JSON.stringify({
        success: true,
        message: `Intent "${args.subject}" marked as complete.`,
        intent_id: targetId,
        note: args.note,
        tracked: false,
      });
    } else {
      return JSON.stringify({
        success: false,
        message: `Could not complete intent "${args.subject}". Intent may not exist or was already completed.`,
        tracked: false,
      });
    }
  },
};

/**
 * Dialogos Observer
 * 
 * Real-time integration of Living Dialogos into the substrate flow.
 * Uses singleton pattern to persist across sessions.
 */

import { LivingDialogos, type StatedIntent } from './live.js';
import * as fs from 'fs';
import * as path from 'path';

const DIALOGOS_STATE_FILE = path.join('history', 'dialogos_state.json');

export interface ObserverConfig {
  enabled: boolean;
  checkInterval: number;
  interruptOnGap: boolean;
  interruptOnMisalignment: boolean;
  minSessionActivity: number;
}

export const DEFAULT_OBSERVER_CONFIG: ObserverConfig = {
  enabled: true,
  checkInterval: 300000,
  interruptOnGap: true,
  interruptOnMisalignment: true,
  minSessionActivity: 5
};

export class DialogosObserver {
  private dialogos: LivingDialogos;
  private config: ObserverConfig;
  private actionCount: number = 0;
  private lastCheck: number = Date.now();
  private sessionStart: number = Date.now();
  private storedIntents: Map<string, StatedIntent[]> = new Map();
  private storedActions: Map<string, any[]> = new Map();

  constructor(config: Partial<ObserverConfig> = {}) {
    this.dialogos = new LivingDialogos();
    this.config = { ...DEFAULT_OBSERVER_CONFIG, ...config };
    this.loadState();
  }

  private loadState() {
    try {
      if (fs.existsSync(DIALOGOS_STATE_FILE)) {
        const state = JSON.parse(fs.readFileSync(DIALOGOS_STATE_FILE, 'utf-8'));
        this.storedIntents = new Map(Object.entries(state.intents || {}));
        this.storedActions = new Map(Object.entries(state.actions || {}));
      }
    } catch {}
  }

  saveState() {
    try {
      const state = {
        intents: Object.fromEntries(this.storedIntents),
        actions: Object.fromEntries(this.storedActions),
        savedAt: new Date().toISOString()
      };
      fs.writeFileSync(DIALOGOS_STATE_FILE, JSON.stringify(state, null, 2));
    } catch {}
  }

  recordAction(type: string, description: string): string | null {
    this.actionCount++;
    this.dialogos.indexSemanticContent(`current_${Date.now()}`, description);

    if (this.shouldInterrupt()) {
      const interruption = this.generateInterruption();
      if (interruption) {
        this.saveState();
        return interruption;
      }
    }
    return null;
  }

  registerStatedIntent(subject: string, description: string, emotionalTone?: string) {
    const intent: StatedIntent = {
      id: `intent_${Date.now()}`,
      description,
      timestamp: Date.now(),
      sessionId: 'current'
    };
    if (emotionalTone) intent.emotionalTone = emotionalTone;
    this.dialogos.registerIntent(subject, intent);

    // Also store persistently
    const existing = this.storedIntents.get(subject) || [];
    existing.push(intent);
    this.storedIntents.set(subject, existing);
    this.saveState();
  }
  /**
   * Mark an intent as completed and remove it from tracking.
   */
  completeIntent(subject: string, intentId: string): boolean {
    const result = this.dialogos.completeIntent(subject, intentId);
    if (result) {
      const existing = this.storedIntents.get(subject);
      if (existing) {
        const filtered = existing.filter(i => i.id !== intentId);
        if (filtered.length === 0) {
          this.storedIntents.delete(subject);
        } else {
          this.storedIntents.set(subject, filtered);
        }
        this.saveState();
      }
    }
    return result;
  }


  recordActivity(activity: string) {
    this.dialogos.recordActivity(Date.now(), activity);
  }

  private shouldInterrupt(): boolean {
    if (!this.config.enabled) return false;
    if (this.actionCount < this.config.minSessionActivity) return false;

    const now = Date.now();
    if (now - this.lastCheck < this.config.checkInterval) return false;

    this.lastCheck = now;
    return true;
  }

  generateInterruption(): string | null {
    const gaps = this.dialogos.detectGaps();
    const misaligned = this.dialogos.findGoalActivityMisalignment();

    if (this.config.interruptOnGap && gaps.length > 0 && gaps[0]) {
      const gap = gaps[0];
      const hours = Math.round(gap.timeSinceStated / 3600000);

      if (gap.status === 'avoided') {
        return `[DIALOGOS INTERRUPT] You mentioned "${gap.intent}" ${hours}h ago but haven't acted. What makes it difficult?`;
      } else if (gap.status === 'forgotten') {
        return `[DIALOGOS INTERRUPT] You forgot: "${gap.intent}". Was it important?`;
      }
    }

    if (this.config.interruptOnMisalignment && misaligned.length > 0 && misaligned[0]) {
      const goal = misaligned[0];
      return `[DIALOGOS INTERRUPT] Goal "${goal.goalName}" has ${(goal.coverage * 100).toFixed(0)}% activity coverage. Where does attention really go?`;
    }

    const questions = this.dialogos.generateBlindSpotQuestions();
    if (questions.length > 0) {
      return `[DIALOGOS REFLECTION] ${questions[0]}`;
    }

    return null;
  }

  getSessionInsights() {
    const now = Date.now();
    const liveState = this.dialogos.queryLiveSession();

    return {
      duration: Math.round((now - this.sessionStart) / 60000),
      actions: this.actionCount,
      dominantConcepts: liveState.dominantConcepts,
      recommendedQuestions: liveState.recommendedQuestions,
      gaps: liveState.gaps.map(g => ({ intent: g.intent, status: g.status }))
    };
  }
}

